import React, { useEffect, useState } from "react";
import axios from "axios";
import "../index.css";

const OrdersPage = () => {
  const [orders, setOrders] = useState([]);

  const fetchOrders = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/orders");
      setOrders(res.data);
    } catch (err) {
      console.error("Failed to fetch orders:", err);
    }
  };

  useEffect(() => {
    fetchOrders();
  }, []);

  const handleCancel = async (orderId) => {
    const reason = prompt("Please enter the reason for cancelling this order:");
    if (!reason) return alert("Cancellation reason is required!");

    try {
      const res = await axios.put(`http://localhost:5000/api/orders/${orderId}/cancel`, {
        cancelReason: reason,
      });
      alert(res.data.message);
      fetchOrders();
    } catch (err) {
      console.error("Cancel error:", err);
      alert("Failed to cancel order");
    }
  };

  return (
    <div className="orders-page">
      <h2>Your Orders</h2>
      {orders.length === 0 ? (
        <p>No orders found.</p>
      ) : (
        <div className="orders-list">
          {orders.map((order) => (
            <div key={order._id} className="order-card">
              <div className="order-header">
                <span>Order #{order._id}</span>
                <span className={`order-status ${order.status.toLowerCase()}`}>
                  {order.status}
                </span>
              </div>

              <p>📅 {order.date}</p>

              <div className="order-items">
                {order.items.map((item, i) => (
                  <div key={i} className="order-item">
                    <img src={item.image || "https://via.placeholder.com/80"} alt={item.name} />
                    <div>
                      <h4>{item.name}</h4>
                      <p>₹{item.price} × {item.quantity}</p>
                    </div>
                  </div>
                ))}
              </div>

              <div className="order-summary">
                <p><strong>Name:</strong> {order.name}</p>
                <p><strong>Mobile:</strong> {order.mobile}</p>
                <p><strong>Address:</strong> {order.address}</p>
                <p><strong>Payment:</strong> {order.payment}</p>
                <p><strong>Total:</strong> ₹{order.total}</p>
              </div>

              {order.status === "Cancelled" ? (
                <div className="cancel-info">
                  <p><strong>Cancelled On:</strong> {order.cancelDate}</p>
                  <p><strong>Reason:</strong> {order.cancelReason}</p>
                </div>
              ) : (
                <button onClick={() => handleCancel(order._id)}>Cancel Order</button>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default OrdersPage;
